import { SCALE_FALLBACK_COLOR } from '../constants.js';

/**
 * Gets color if it's a valid CSS color, otherwise returns the default.
 *
 * @param color - color to validate
 */
export function getValidColor(
  color: string = '',
  defaultColor: string = SCALE_FALLBACK_COLOR,
) {
  if (isValidCSSColor(color)) {
    return color;
  }

  return defaultColor;
}

export const isValidCSSColor = (color: string) => {
  if (color === 'initial' || color === 'inherit') {
    return true;
  }

  const { style } = new Option();

  style.color = color.startsWith('var(')
    ? /**
       * FYI: If the color starts with 'var(', extract the fallback color from the CSS variable definition
       * Example: 'var(--primary-color, #ff0000)' -> '#ff0000'
       */
      color.replace(/^\s*var\(--[0-9A-Za-z-]+,\s*([^)]+)\)\s*$/, '$1')
    : color;

  return style.color !== '';
};
